#include <bits/stdc++.h>
using namespace std;
const int N=11,M=1<<10,mod=1e9+7;
int x,y,g[105],dp[2][M][M];
int cnt[M];
int main()
{
    cin>>x>>y;
    for(int i=0;i<(1<<y);i++) dp[1][i][0]=1;
    for(int i=2;i<=x;i++)
    {
        for(int a=0;a<(1<<y);a++)
        {
            for(int b=0;b<(1<<y);b++)
            {
                dp[i%2][a][b]=0;
                if(((a)&(~a>>1)&(b>>2))||
                ((a)&(~a<<1)&(b<<2))||
                ((b)&(~b>>1)&(a>>2))||
                ((b)&(~b<<1)&(a<<2))) continue;
                for(int c=0;c<(1<<y);c++)
                {
                    if((a&(~b)&(c>>1))||
                    (a&(~b)&(c<<1))||
                    (c&(~b)&(a>>1))||
                    (c&(~b)&(a<<1))) continue;
                    dp[i%2][a][b]+=dp[(i-1)%2][b][c];
                    dp[i%2][a][b]%=mod;
                }
            }
        }
    }
    long long ans=0;
    for(int i=0;i<(1<<y);i++)
    {
        for(int j=0;j<(1<<y);j++)
        {
            ans+=dp[x%2][i][j];
            ans%=mod;
        }
    }
    cout<<ans;
    return 0;
}
